2596	\begin{lemma}[Qcqs lemma: structure-sheaf sections on a basic open localize]
2597	  \label{lem:isLocalization_basicOpen_of_qcqs_mathlib}
2598	  \lean{AlgebraicGeometry.isLocalization_basicOpen_of_qcqs}
2599	  \mathlibok
2600	  \textit{Provided by Mathlib
2601	  (\texttt{Mathlib.AlgebraicGeometry.Morphisms.QuasiSeparated}); the structure-sheaf
2602	  template for the module descent below.}
2603	  Let \(X\) be a scheme, \(U \subseteq X\) a quasi-compact and quasi-separated open, and
2604	  \(f \in \Gamma(X, U)\). Then the restriction \(\Gamma(X, U) \to \Gamma(X, D(f))\) exhibits
2605	  \(\Gamma(X, D(f))\) as the localization \(\Gamma(X,U)_f\); that is, it is
2606	  \(\mathrm{IsLocalization.Away}\,f\). Mathlib assembles this from the three pointwise axioms of
2607	  \(\mathrm{IsLocalization.Away}\) by compact-open induction and sheaf gluing, without constructing
2608	  an equalizer object and without invoking flatness; \cref{lem:qcoh_affine_section_localization} is
2609	  its module analogue.
2610	\end{lemma}
